---@type LxAudio
local LxAudio = require("LApp.component.media.LxAudio")

---@class LxSoundGroup
local LxSoundGroup = classX("LxSoundGroup", nil)

local Time = Time

function LxSoundGroup:LxSoundGroup(audioSourceList)
    local audios = {}
    for k,audioSource in ipairs(audioSourceList) do
        local audio = LxAudio:New(audioSource)
        audio:SetLoadedFunc(self.OnLoaded, self)
        table.insert(audios, audio)
    end

    ---@type LxAudio[]
    self._audioList = audios

    ---@type table<string, number>
    self._frameMap = {}

    self._recordFrame = 0
end

function LxSoundGroup:Initialize()
    self._bLoop = false
    self._pitch = 1
    self._volume = 1
    self._isMute = false
end

function LxSoundGroup:Dispose()
    if self._isDisposed then return end
    self:StopSound()
    table.dispose(self)
    self._isDisposed = true
end

function LxSoundGroup:SetMute(value)
    self._isMute = value
    self:UpdateMute()
end

function LxSoundGroup:SetVolume(vol)
    self._volume = vol
    self:UpdateVolume()
end

function LxSoundGroup:UpdateVolume()
    if not self._audioList then
        return
    end
    local volume = self._volume
    local list = self._audioList
    for k,audio in ipairs(list) do
        audio:SetVolume(volume)
    end
end

function LxSoundGroup:UpdateMute()
    if not self._audioList then
        return
    end
    local mute = self._isMute
    local list = self._audioList
    for k,audio in ipairs(list) do
        audio:SetMute(mute)
    end
end

---同一帧不重复播放同样的音频
function LxSoundGroup:CheckPlayValid(audioName)
    local frame = Time.frameCount
    if self._recordFrame ~= frame then
        self._recordFrame = frame
        self._frameMap = {}
    end
    local count = self._frameMap[audioName] or 0
    if count >= 1 then
        return false
    end
    self._frameMap[audioName] = count + 1
    return true
end

function LxSoundGroup:PlaySound(audioName)
    if not self._audioList then return end
    if self._isMute then return end

    if not self:CheckPlayValid(audioName) then
        if LOG_INFO_ENABLED then
            printInfo("audio", "忽略同一帧重复播放的音频 ： %s", audioName)
        end
        return
    end

    local frame = Time.frameCount
    for k,audio in ipairs(self._audioList) do
        ---同一帧不重复检测
        if not audio:IsCheckPlayingFrame(frame) then
            audio:SetCheckPlayingFrame(frame)
            if audio:IsDone() and not audio:IsPlaying() then
                audio:LoadAudio(audioName)
                return
            end
        end
    end

    if LOG_INFO_ENABLED then
        printInfo("audio", "未找到空闲的播放器，忽略播放音频 ： %s", audioName)
    end
end

function LxSoundGroup:StopSound()
    if not self._audioList then return end

    local list = self._audioList
    for k,audio in ipairs(list) do
        audio:StopPlay()
    end
end

---@param audio LxAudio
function LxSoundGroup:OnLoaded(audio, audioClip, audioName)
    local audioSource = audio:GetAudioSource()
    local pitch = self._pitch --Time.timeScale
    audioSource.clip = audioClip
    audioSource.loop = self._bLoop
    audioSource.pitch = pitch
    audioSource:Play()
end

function LxSoundGroup:Play()
    if not self._audioList then return end
    local list = self._audioList
    for k,audio in ipairs(list) do
        audio:Play()
    end
end

function LxSoundGroup:Resume()
    if not self._audioList then return end
    local list = self._audioList
    for k,audio in ipairs(list) do
        audio:Resume()
    end
end

function LxSoundGroup:Pause()
    if not self._audioList then return end
    local list = self._audioList
    for k,audio in ipairs(list) do
        audio:Pause()
    end
end

return LxSoundGroup